import json

with open('paper/dana_benchmark.ipynb') as f:
    nb = json.load(f)

print(f"Valid JSON: {len(nb['cells'])} cells")

# Check no [:5] or [:3] limits remain
for i, cell in enumerate(nb['cells']):
    src = ''.join(cell['source'])
    if '[:5]' in src or '[:3]' in src:
        # Check these aren't in loops indexing instances
        covered = False
        if 'instance_files' not in src and 'x_files' not in src and 'bench_files' not in src:
            covered = True
        if not covered:
            for j, line in enumerate(cell['source']):
                if ('[:5]' in line or '[:3]' in line):
                    print(f"  WARNING: Cell {i} still has limit: {line.strip()}")

# Check ML section runs on all benchmarks
cell = nb['cells'][30]
src = ''.join(cell['source'])
if 'ML_BENCHMARKS' in src:
    print("  ML models now run on all benchmarks")
if 'for inst_file in bench_files:' in src:
    print("  ML models loop over all instances (no limit)")

print("\nDone - notebook ready")
PYEOF

