import json

with open('dana_benchmark.ipynb') as f:
    nb = json.load(f)

# Check HGS compilation cell
for i, cell in enumerate(nb['cells']):
    src = ''.join(cell['source'])
    if 'HGS-CVRP' in src and 'make' in src and 'j\$(nproc)' in src:
        print(f"Cell {i} has HGS compilation with -j$(nproc):")
        for j, line in enumerate(cell['source']):
            if 'make' in line and 'nproc' in line:
                print(f"  Line {j}: {line!r}")
    if 'LKH-3' in src and 'make' in src:
        print(f"Cell {i} has LKH compilation:")
        for j, line in enumerate(cell['source']):
            if 'make' in line or 'cmake' in line or 'LKH' in line:
                print(f"  Line {j}: {line!r}")
PYEOF
